       const content = fs.readFileSync(
         path.join(skillsDir, dir, "SKILL.md"),
         "utf-8"
       );
       const match = content.match(/^name:\s*(\S+)/m);
       expect(match).not.toBeNull();
       expect(match[1]).toBe(dir);
     }
   });
